const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const regs = JSON.parse(localStorage.getItem('program_registrations') || '[]');

function overlapsAgeRange(pMin, pMax, qMin, qMax) {
  if (pMin == null || pMax == null) return false;
  return !(pMin > qMax || pMax < qMin);
}

function isQualifyingProgram(p) {
  if (!p) return false;
  if (p.status !== 'active') return false;
  if (p.category_id !== 'swim_lessons_kids') return false;
  if (p.subcategory !== 'kids_group_lesson') return false;
  if (p.skill_level !== 'beginner_1') return false;
  const pMin = typeof p.age_min === 'number' ? p.age_min : null;
  const pMax = typeof p.age_max === 'number' ? p.age_max : null;
  if (!overlapsAgeRange(pMin, pMax, 6, 8)) return false;
  if (!p.start_time || p.start_time < '16:00') return false;
  const price = typeof p.price === 'number' ? p.price : 0;
  if (price > 120) return false;
  return true;
}

const qualifyingPrograms = programs.filter(isQualifyingProgram);
let earliestProgram = null;
if (qualifyingPrograms.length > 0) {
  const sorted = qualifyingPrograms.slice().sort((a, b) => {
    const da = new Date(a.start_date || 0).getTime();
    const db = new Date(b.start_date || 0).getTime();
    if (da !== db) return da - db;
    const ta = a.start_time || '';
    const tb = b.start_time || '';
    if (ta < tb) return -1;
    if (ta > tb) return 1;
    return 0;
  });
  earliestProgram = sorted[0] || null;
}

const regsWithPrograms = regs.map(r => ({ reg: r, program: programs.find(p => p.id === r.program_id) || null }));

const qualifyingRegistrations = regsWithPrograms.filter(x => isQualifyingProgram(x.program));

// CP1 (0.4): User registered for at least one qualifying program (correct age range, level, time, and price).
checkpoints.push({ passed: qualifyingRegistrations.length > 0, weight: 0.4 });

// CP2 (0.6): Among qualifying options, user registered specifically for the earliest qualifying program.
let registeredEarliest = false;
if (earliestProgram) {
  registeredEarliest = qualifyingRegistrations.some(x => x.program && x.program.id === earliestProgram.id);
}
checkpoints.push({ passed: !!earliestProgram && registeredEarliest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const slots = JSON.parse(localStorage.getItem('lap_lane_slots') || '[]');
const reservations = JSON.parse(localStorage.getItem('lap_lane_reservations') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let baselineStart = null;
let tomorrow = null;
if (baselineStr) {
  baselineStart = new Date(baselineStr + 'T00:00:00');
  tomorrow = new Date(baselineStart.getTime() + 24 * 60 * 60 * 1000);
}

function sameDate(dateIso, dateObj) {
  if (!dateIso || !dateObj) return false;
  const d1 = new Date(dateIso);
  return d1.getFullYear() === dateObj.getFullYear() && d1.getMonth() === dateObj.getMonth() && d1.getDate() === dateObj.getDate();
}

function timeStrFrom(dateIso) {
  const d = new Date(dateIso || '');
  if (isNaN(d.getTime())) return null;
  const hh = (d.getHours() < 10 ? '0' : '') + d.getHours();
  const mm = (d.getMinutes() < 10 ? '0' : '') + d.getMinutes();
  return hh + ':' + mm;
}

function isQualifyingSlot(s) {
  if (!tomorrow) return false;
  if (!sameDate(s.slot_date, tomorrow)) return false;
  if (s.pool_type !== 'indoor') return false;
  const startStr = timeStrFrom(s.start_datetime || s.slot_date);
  const endStr = timeStrFrom(s.end_datetime || s.slot_date);
  if (!startStr || !endStr) return false;
  if (startStr < '06:00' || startStr > '07:00') return false;
  // Require that the slot ends by 07:00 so it is fully within 6–7 AM
  if (endStr > '07:00') return false;
  const price = typeof s.price === 'number' ? s.price : 0;
  if (price > 15) return false;
  return true;
}

const qualifyingSlots = slots.filter(isQualifyingSlot);
let cheapestSlot = null;
if (qualifyingSlots.length > 0) {
  const sorted = qualifyingSlots.slice().sort((a, b) => {
    const pa = typeof a.price === 'number' ? a.price : 0;
    const pb = typeof b.price === 'number' ? b.price : 0;
    if (pa !== pb) return pa - pb;
    const ta = timeStrFrom(a.start_datetime || a.slot_date) || '';
    const tb = timeStrFrom(b.start_datetime || b.slot_date) || '';
    if (ta < tb) return -1;
    if (ta > tb) return 1;
    return 0;
  });
  cheapestSlot = sorted[0] || null;
}

const newReservations = reservations.filter(r => {
  if (!baselineStart) return true;
  const created = new Date(r.created_at || 0);
  return created >= baselineStart;
});

const qualifyingReservations = newReservations.filter(r => {
  const slot = slots.find(s => s.id === r.lap_lane_slot_id);
  if (!slot) return false;
  if (!isQualifyingSlot(slot)) return false;
  return true;
});

// CP1 (0.4): User reserved at least one lap lane slot that meets all criteria (indoor, tomorrow, 6–7 AM, price ≤ $15).
checkpoints.push({ passed: qualifyingReservations.length > 0, weight: 0.4 });

// CP2 (0.6): The user reserved the cheapest qualifying slot among all such options.
let reservedCheapest = false;
if (cheapestSlot) {
  reservedCheapest = qualifyingReservations.some(r => r.lap_lane_slot_id === cheapestSlot.id);
}
checkpoints.push({ passed: !!cheapestSlot && reservedCheapest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('membership_plans') || '[]');
const purchases = JSON.parse(localStorage.getItem('membership_purchases') || '[]');
let comparedIds = [];
try {
  comparedIds = JSON.parse(localStorage.getItem('task3_comparedPlanIds') || '[]') || [];
  if (!Array.isArray(comparedIds)) comparedIds = [];
} catch (e) {
  comparedIds = [];
}
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let baselineStart = null;
if (baselineStr) baselineStart = new Date(baselineStr + 'T00:00:00');

function isQualifyingPlan(p) {
  if (!p) return false;
  if (p.status !== 'active') return false;
  if (p.membership_type !== 'family') return false;
  if (p.duration !== 'one_month') return false;
  if (!p.pool_access_included) return false;
  if (!p.fitness_center_included) return false;
  const price = typeof p.price === 'number' ? p.price : 0;
  if (price > 120) return false;
  const close = p.weekday_close_time || '00:00';
  if (close < '22:00') return false;
  return true;
}

const qualifyingPlans = plans.filter(isQualifyingPlan);
let bestPlan = null;
if (qualifyingPlans.length > 0) {
  const sorted = qualifyingPlans.slice().sort((a, b) => {
    const ca = a.weekday_close_time || '00:00';
    const cb = b.weekday_close_time || '00:00';
    if (ca < cb) return 1;
    if (ca > cb) return -1;
    const pa = typeof a.price === 'number' ? a.price : 0;
    const pb = typeof b.price === 'number' ? b.price : 0;
    return pa - pb;
  });
  bestPlan = sorted[0] || null;
}

const qualifyingCompared = comparedIds.filter(id => {
  const p = plans.find(pl => pl.id === id);
  return isQualifyingPlan(p);
});

const recentPurchases = purchases.filter(p => {
  if (!baselineStart) return true;
  const created = new Date(p.created_at || 0);
  return created >= baselineStart;
});

const qualifyingPurchases = recentPurchases.filter(mp => {
  const p = plans.find(pl => pl.id === mp.membership_plan_id);
  return isQualifyingPlan(p);
});

// CP1 (0.2): User viewed/compared at least one qualifying plan that meets all constraints.
checkpoints.push({ passed: qualifyingCompared.length > 0, weight: 0.2 });

// CP2 (0.3): User purchased at least one qualifying membership plan.
checkpoints.push({ passed: qualifyingPurchases.length > 0, weight: 0.3 });

// CP3 (0.5): User purchased the optimal plan (latest closing time, lowest price on tie) among qualifying options.
let purchasedBest = false;
if (bestPlan) {
  purchasedBest = qualifyingPurchases.some(mp => mp.membership_plan_id === bestPlan.id);
}
checkpoints.push({ passed: !!bestPlan && purchasedBest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('party_packages') || '[]');
const reservations = JSON.parse(localStorage.getItem('party_reservations') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let baselineStart = null;
if (baselineStr) baselineStart = new Date(baselineStr + 'T00:00:00');

const CHILDREN_COUNT = 15;
const MAX_TOTAL = 350;

function computeTotalPrice(pkg, size) {
  if (!pkg) return 0;
  const base = typeof pkg.base_price === 'number' ? pkg.base_price : 0;
  const included = typeof pkg.included_children_count === 'number' ? pkg.included_children_count : 0;
  const fee = typeof pkg.additional_child_fee === 'number' ? pkg.additional_child_fee : 0;
  const extra = size > included ? (size - included) : 0;
  return base + extra * fee;
}

function isPackageQualifying(pkg, size) {
  if (!pkg) return false;
  if (pkg.status !== 'active') return false;
  if (pkg.category !== 'birthday_party') return false;
  if (!pkg.includes_private_party_room) return false;
  if (!pkg.includes_pizza) return false;
  if (typeof size === 'number') {
    if (typeof pkg.min_children === 'number' && size < pkg.min_children) return false;
    if (typeof pkg.max_children === 'number' && size > pkg.max_children) return false;
  }
  const total = computeTotalPrice(pkg, size);
  if (total > MAX_TOTAL) return false;
  return true;
}

function dayOfWeekId(dateIso) {
  if (!dateIso) return null;
  const d = new Date(dateIso);
  if (isNaN(d.getTime())) return null;
  const map = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
  return map[d.getDay()];
}

const qualifyingPackages = packages.filter(p => isPackageQualifying(p, CHILDREN_COUNT));
let cheapestPackage = null;
if (qualifyingPackages.length > 0) {
  const sorted = qualifyingPackages.slice().sort((a, b) => computeTotalPrice(a, CHILDREN_COUNT) - computeTotalPrice(b, CHILDREN_COUNT));
  cheapestPackage = sorted[0] || null;
}

const newReservations = reservations.filter(r => {
  if (!baselineStart) return true;
  const created = new Date(r.created_at || 0);
  return created >= baselineStart;
});

const qualifyingReservations = newReservations.filter(r => {
  if (r.party_size_children !== CHILDREN_COUNT) return false;
  const pkg = packages.find(p => p.id === r.party_package_id);
  if (!isPackageQualifying(pkg, r.party_size_children)) return false;
  const dayId = dayOfWeekId(r.selected_date);
  if (dayId !== 'saturday') return false;
  if (Array.isArray(pkg.available_days_of_week) && pkg.available_days_of_week.length > 0) {
    if (pkg.available_days_of_week.indexOf(dayId) === -1) return false;
  }
  const total = computeTotalPrice(pkg, r.party_size_children);
  if (total > MAX_TOTAL) return false;
  return true;
});

// CP1 (0.4): User created at least one reservation that meets all constraints (Saturday, 15 kids, private room, pizza, total price ≤ $350, package supports that size and day).
checkpoints.push({ passed: qualifyingReservations.length > 0, weight: 0.4 });

// CP2 (0.6): The reservation uses the cheapest qualifying package for 15 children.
let reservedCheapest = false;
if (cheapestPackage) {
  reservedCheapest = qualifyingReservations.some(r => r.party_package_id === cheapestPackage.id);
}
checkpoints.push({ passed: !!cheapestPackage && reservedCheapest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sessions = JSON.parse(localStorage.getItem('pool_schedule_sessions') || '[]');
const myItems = JSON.parse(localStorage.getItem('my_schedule_items') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let nextMonday = null;
let nextSunday = null;
if (baselineStr) {
  const base = new Date(baselineStr + 'T00:00:00');
  const day = base.getDay(); // 0=Sun
  const offsetToMonday = (day + 6) % 7; // days to subtract to get Monday
  const thisMonday = new Date(base.getTime());
  thisMonday.setDate(base.getDate() - offsetToMonday);
  nextMonday = new Date(thisMonday.getTime());
  nextMonday.setDate(thisMonday.getDate() + 7);
  nextSunday = new Date(nextMonday.getTime());
  nextSunday.setDate(nextMonday.getDate() + 6);
}

function timeStrFrom(dateIso) {
  const d = new Date(dateIso || '');
  if (isNaN(d.getTime())) return null;
  const hh = (d.getHours() < 10 ? '0' : '') + d.getHours();
  const mm = (d.getMinutes() < 10 ? '0' : '') + d.getMinutes();
  return hh + ':' + mm;
}

function inNextWeek(session) {
  if (!nextMonday || !nextSunday) return false;
  const d = new Date(session.session_date || session.start_datetime || '');
  if (isNaN(d.getTime())) return false;
  return d >= nextMonday && d <= nextSunday;
}

const itemsWithSessions = myItems
  .filter(it => it.item_type === 'open_swim_session')
  .map(it => {
    const session = sessions.find(s => s.id === it.pool_schedule_session_id) || null;
    return { item: it, session };
  })
  .filter(x => x.session && x.session.activity_type === 'open_swim');

const qualifying = itemsWithSessions.filter(x => {
  const s = x.session;
  if (!inNextWeek(s)) return false;
  const startStr = timeStrFrom(s.start_datetime);
  if (!startStr || startStr < '17:00') return false;
  return true;
});

// Deduplicate by session id so we count distinct sessions
const seen = {};
const distinctQualifying = [];
for (const x of qualifying) {
  const sid = x.session.id;
  if (!sid) continue;
  if (!seen[sid]) {
    seen[sid] = true;
    distinctQualifying.push(x);
  }
}

const indoorSessions = distinctQualifying.filter(x => x.session.pool_type === 'indoor');
const outdoorSessions = distinctQualifying.filter(x => x.session.pool_type === 'outdoor');

let hasIndoorOutdoorDifferentDays = false;
if (indoorSessions.length > 0 && outdoorSessions.length > 0) {
  for (let i = 0; i < indoorSessions.length && !hasIndoorOutdoorDifferentDays; i++) {
    for (let j = 0; j < outdoorSessions.length && !hasIndoorOutdoorDifferentDays; j++) {
      if (indoorSessions[i].session.day_of_week !== outdoorSessions[j].session.day_of_week) {
        hasIndoorOutdoorDifferentDays = true;
      }
    }
  }
}

// CP1 (0.4): At least three distinct qualifying open swim sessions added (next week, start ≥ 17:00).
checkpoints.push({ passed: distinctQualifying.length >= 3, weight: 0.4 });

// CP2 (0.6): Among qualifying sessions, there is at least one indoor and one outdoor session on different weekdays.
checkpoints.push({ passed: hasIndoorOutdoorDifferentDays, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const passProducts = JSON.parse(localStorage.getItem('pass_products') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const orderItems = JSON.parse(localStorage.getItem('order_items') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let baselineStart = null;
if (baselineStr) baselineStart = new Date(baselineStr + 'T00:00:00');

const DESIRED_VISITS = 5;
const MAX_TOTAL_PRICE = 60;

// Compute best possible total cost based on available products
const candidateOptions = [];
for (const p of passProducts) {
  if (!p || !p.is_active) continue;
  if (p.pass_type !== 'guest_passes') continue;
  if (p.format !== 'digital_pass') continue;
  const visitsPer = typeof p.visits_per_pass === 'number' ? p.visits_per_pass : 0;
  const price = typeof p.price === 'number' ? p.price : 0;
  if (visitsPer <= 0) continue;
  if (DESIRED_VISITS % visitsPer !== 0) continue;
  const qty = DESIRED_VISITS / visitsPer;
  const totalCost = price * qty;
  if (totalCost > MAX_TOTAL_PRICE) continue;
  candidateOptions.push({ product: p, quantity: qty, totalCost });
}
let bestTotalCost = null;
if (candidateOptions.length > 0) {
  bestTotalCost = candidateOptions.reduce((min, opt) => (min === null || opt.totalCost < min ? opt.totalCost : min), null);
}

// Find new orders since baseline
const recentOrders = orders.filter(o => {
  if (!baselineStart) return true;
  const created = new Date(o.created_at || 0);
  return created >= baselineStart;
});
const recentOrderIds = recentOrders.map(o => o.id);

const relevantOrderItems = orderItems.filter(oi => oi.item_type === 'pass_product' && recentOrderIds.indexOf(oi.order_id) !== -1);

const qualifyingPurchases = [];
for (const oi of relevantOrderItems) {
  const product = passProducts.find(p => p.id === oi.pass_product_id);
  if (!product || !product.is_active) continue;
  if (product.pass_type !== 'guest_passes') continue;
  if (product.format !== 'digital_pass') continue;
  const visitsPer = typeof product.visits_per_pass === 'number' ? product.visits_per_pass : 0;
  const qty = typeof oi.quantity === 'number' ? oi.quantity : 0;
  const totalVisits = visitsPer * qty;
  const totalPrice = typeof oi.total_price === 'number' ? oi.total_price : (typeof oi.unit_price === 'number' ? oi.unit_price * qty : 0);
  if (totalVisits !== DESIRED_VISITS) continue;
  if (totalPrice > MAX_TOTAL_PRICE) continue;
  qualifyingPurchases.push({ orderItem: oi, product, totalPrice });
}

// CP1 (0.4): User purchased at least one pass-product order item that yields exactly 5 visits with total price ≤ $60.
checkpoints.push({ passed: qualifyingPurchases.length > 0, weight: 0.4 });

// CP2 (0.6): At least one qualifying purchase matches the lowest possible total cost among all valid product combinations.
let purchasedBest = false;
if (bestTotalCost !== null) {
  purchasedBest = qualifyingPurchases.some(qp => Math.abs(qp.totalPrice - bestTotalCost) < 0.001);
}
checkpoints.push({ passed: bestTotalCost !== null && purchasedBest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const regs = JSON.parse(localStorage.getItem('program_registrations') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let baselineStart = null;
if (baselineStr) baselineStart = new Date(baselineStr + 'T00:00:00');

const MAX_PRICE = 300;
const END_BEFORE = new Date('2026-06-30T00:00:00');

function isQualifyingProgram(p) {
  if (!p) return false;
  if (p.status !== 'active') return false;
  if (p.category_id !== 'training_certifications') return false;
  if (p.subcategory !== 'lifeguard_certification') return false;
  if (!p.includes_cpr_first_aid) return false;
  if (!p.is_weekends_only) return false;
  const price = typeof p.price === 'number' ? p.price : 0;
  if (price > MAX_PRICE) return false;
  if (p.end_date) {
    const end = new Date(p.end_date);
    if (end > END_BEFORE) return false;
  }
  return true;
}

const qualifyingPrograms = programs.filter(isQualifyingProgram);
let bestProgram = null;
if (qualifyingPrograms.length > 0) {
  const sorted = qualifyingPrograms.slice().sort((a, b) => {
    const da = typeof a.total_duration_hours === 'number' ? a.total_duration_hours : Number.POSITIVE_INFINITY;
    const db = typeof b.total_duration_hours === 'number' ? b.total_duration_hours : Number.POSITIVE_INFINITY;
    return da - db;
  });
  bestProgram = sorted[0] || null;
}

const recentRegs = regs.filter(r => {
  if (!baselineStart) return true;
  const created = new Date(r.created_at || 0);
  return created >= baselineStart;
});

const qualifyingRegistrations = recentRegs.filter(r => {
  if (r.registration_type !== 'lifeguard_certification') return false;
  const p = programs.find(pr => pr.id === r.program_id);
  return isQualifyingProgram(p);
});

// CP1 (0.4): User enrolled in at least one qualifying lifeguard certification course matching all constraints.
checkpoints.push({ passed: qualifyingRegistrations.length > 0, weight: 0.4 });

// CP2 (0.6): The enrolled course is the shortest-duration qualifying option.
let enrolledBest = false;
if (bestProgram) {
  enrolledBest = qualifyingRegistrations.some(r => r.program_id === bestProgram.id);
}
checkpoints.push({ passed: !!bestProgram && enrolledBest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('programs') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const orderItems = JSON.parse(localStorage.getItem('order_items') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let baselineStart = null;
if (baselineStr) baselineStart = new Date(baselineStr + 'T00:00:00');

const MAX_PRICE_PER_CLASS = 20;

function isQualifyingClass(p) {
  if (!p) return false;
  if (p.status !== 'active') return false;
  if (p.category_id !== 'fitness_classes') return false;
  if (p.subcategory !== 'aqua_fitness') return false;
  const price = typeof p.price === 'number' ? p.price : 0;
  if (price > MAX_PRICE_PER_CLASS) return false;
  const start = p.start_time || '';
  if (start < '18:00' || start > '20:00') return false;
  return true;
}

function getClassType(p) {
  if (!p || typeof p.name !== 'string') return '';
  const parts = p.name.split('–');
  return parts[0].trim();
}

function timeToMinutes(t) {
  if (!t || typeof t !== 'string') return null;
  const parts = t.split(':');
  if (parts.length < 2) return null;
  const h = parseInt(parts[0], 10);
  const m = parseInt(parts[1], 10);
  if (isNaN(h) || isNaN(m)) return null;
  return h * 60 + m;
}

function timesOverlap(p1, p2) {
  const s1 = timeToMinutes(p1.start_time);
  const e1 = timeToMinutes(p1.end_time);
  const s2 = timeToMinutes(p2.start_time);
  const e2 = timeToMinutes(p2.end_time);
  if (s1 == null || e1 == null || s2 == null || e2 == null) return true; // treat unknown as overlapping
  return s1 < e2 && s2 < e1;
}

const recentOrders = orders.filter(o => {
  if (!baselineStart) return true;
  const created = new Date(o.created_at || 0);
  return created >= baselineStart;
});
const recentOrderIds = recentOrders.map(o => o.id);

const programPurchases = orderItems
  .filter(oi => oi.item_type === 'program' && recentOrderIds.indexOf(oi.order_id) !== -1)
  .map(oi => {
    const p = programs.find(pr => pr.id === oi.program_id || pr.id === oi.item_ref_id) || null;
    return { orderItem: oi, program: p };
  })
  .filter(x => isQualifyingClass(x.program));

// Deduplicate by program id so we count distinct classes
const seenProg = {};
const distinctPrograms = [];
for (const x of programPurchases) {
  const p = x.program;
  if (!p || !p.id) continue;
  if (!seenProg[p.id]) {
    seenProg[p.id] = true;
    distinctPrograms.push(p);
  }
}

const earlyDays = ['monday', 'tuesday'];
const lateDays = ['wednesday', 'thursday', 'friday'];

let hasValidPair = false;
for (let i = 0; i < distinctPrograms.length && !hasValidPair; i++) {
  const p1 = distinctPrograms[i];
  const d1 = Array.isArray(p1.meeting_days) && p1.meeting_days.length > 0 ? p1.meeting_days[0] : null;
  if (!d1 || earlyDays.indexOf(d1) === -1) continue;
  for (let j = 0; j < distinctPrograms.length && !hasValidPair; j++) {
    if (j === i) continue;
    const p2 = distinctPrograms[j];
    const d2 = Array.isArray(p2.meeting_days) && p2.meeting_days.length > 0 ? p2.meeting_days[0] : null;
    if (!d2 || lateDays.indexOf(d2) === -1) continue;
    const type1 = getClassType(p1);
    const type2 = getClassType(p2);
    if (!type1 || !type2 || type1 === type2) continue;
    if (timesOverlap(p1, p2)) continue;
    hasValidPair = true;
  }
}

// CP1 (0.4): User purchased at least two distinct qualifying aqua fitness classes (evening, price ≤ $20).
checkpoints.push({ passed: distinctPrograms.length >= 2, weight: 0.4 });

// CP2 (0.6): Among those, there exists a pair satisfying the day-of-week split (Mon/Tue vs Wed/Thu/Fri), different class types, and non-overlapping times.
checkpoints.push({ passed: hasValidPair, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
